1	/**
2	 * @file    mqtt_ha.c
3	 * @brief   MQTT + Home Assistant 集成模块实现
4	 *
5	 * 本文件实现了 ESP32 通过 MQTT 协议接入 Home Assistant 的完整逻辑：
6	 *
7	 *   【发现阶段】
8	 *   当 MQTT 连接成功后，自动向 Home Assistant 发送"发现配置"消息。
9	 *   HA 的 MQTT Discovery 机制会自动在界面上创建对应的实体，
10	 *   无需用户在 configuration.yaml 中手动配置。
11	 *
12	 *   【实体列表】
13	 *   - light/<device_id>_pwm       → PWM 驱动的 RGB 灯（如共阳/共阴灯珠）
14	 *   - light/<device_id>_ws2812    → WS2812 可寻址 RGB 灯带
15	 *   - sensor/<device_id>/rssi     → Wi-Fi RSSI 信号强度传感器
16	 *
17	 *   【命令处理】
18	 *   订阅每个实体对应的 command topic，接收 HA 发来的 JSON 格式命令：
19	 *     {
20	 *       "state": "ON"|"OFF",
21	 *       "brightness": 0-255,
22	 *       "color": {"r": 0-255, "g": 0-255, "b": 0-255}
23	 *     }
24	 *   解析后将状态写入 led_control 模块驱动硬件，并通过 state topic 反馈结果。
25	 *
26	 *   【状态反馈】
27	 *   每次灯光状态变更后，立即通过对应的 state topic 发布完整 JSON 状态。
28	 *   使用 retain 标志确保 HA 重新订阅时能立即获得最新状态。
29	 *
30	 *   【遗嘱机制（LWT）】
31	 *   配置 MQTT Last Will：当设备异常断开时，Broker 自动发布 "offline"
32	 *   到 availability 主题，Home Assistant 会将设备标记为"不可用"。
33	 *   正常连接后发布 "online" 恢复可用状态。
34	 */
35	
36	#include "mqtt_ha.h"
37	#include "device_id.h"
38	#include "led_control.h"
39	#include "cJSON.h"
40	#include "esp_log.h"
41	#include "esp_mac.h"
42	#include <string.h>
43	#include <stdio.h>
44	
45	static const char *TAG = "mqtt_ha";
46	
47	/** @brief MQTT 客户端句柄，由 mqtt_ha_init() 创建并持有 */
48	static esp_mqtt_client_handle_t mqtt_client = NULL;
49	
50	/*===========================================================================
51	 * 前向声明（静态函数）
52	 *===========================================================================*/
53	
54	/** @brief 发布 PWM 灯的当前状态到 MQTT state topic */
55	static void publish_pwm_state(void);
56	
57	/** @brief 发布 WS2812 灯带的当前状态到 MQTT state topic */
58	static void publish_ws2812_state(void);
59	
60	/** @brief 解析并执行 PWM 灯的控制命令（来自 MQTT command topic） */
61	static void handle_pwm_command(const char *data, int data_len);
62	
63	/** @brief 解析并执行 WS2812 灯带的控制命令（来自 MQTT command topic） */
64	static void handle_ws2812_command(const char *data, int data_len);
65	
66	/** @brief MQTT 事件分发回调，处理连接、数据接收等事件 */
67	static void mqtt_event_handler(void *handler_args, esp_event_base_t base,
68	                               int32_t event_id, void *event_data);
69	
70	/*===========================================================================
71	 * 公开 API
72	 *===========================================================================*/
73	
74	/**
75	 * @brief  获取 MQTT 客户端句柄（供其他模块使用）
76	 *
77	 * 典型用途：rssi_reporter 通过该句柄发布 RSSI 测量数据。
78	 *
79	 * @return esp_mqtt_client_handle_t  有效的客户端句柄或 NULL
80	 */
81	esp_mqtt_client_handle_t mqtt_ha_get_client(void)
82	{
83	    return mqtt_client;
84	}
85	
86	/**
87	 * @brief  向 MQTT Broker 发布一条消息（线程安全）
88	 *
89	 * 说明：
90	 *  - 如果 mqtt_client 未初始化（为 NULL），函数安全返回，不执行任何操作。
91	 *    这避免了在 Wi-Fi 未连接或 MQTT 未就绪时发生空指针访问。
92	 *  - QoS 固定为 1（至少一次送达），retain 由调用方决定。
93	 *  - 通常用于：
94	 *      * 发布"发现配置"消息（retain = 1）
95	 *      * 发布设备在线/离线状态（retain = 1）
96	 *      * 发布灯光状态（retain = 1）
97	 *      * 发布 RSSI 读数（retain = 1）
98	 *
99	 * @param topic   MQTT 主题字符串
100	 * @param payload 消息体（JSON 字符串或纯文本）
101	 * @param retain  是否保留消息：1 = Broker 存储最后一条消息，新订阅者立即获取
102	 */
103	void mqtt_ha_publish(const char *topic, const char *payload, int retain)
104	{
105	    if (mqtt_client)
106	    {
107	        // QoS=1 确保至少一次送达，retain 由调用者决定
108	        esp_mqtt_client_publish(mqtt_client, topic, payload, 0, 1, retain);
109	    }
110	}
111	
112	/*===========================================================================
113	 * 状态发布函数
114	 *===========================================================================*/
115	
116	/**
117	 * @brief  将 PWM RGB 灯的当前状态序列化为 JSON 并发布
118	 *
119	 * 发布的 JSON 格式示例：
120	 *   {
121	 *     "state": "ON",
122	 *     "brightness": 200,
123	 *     "color_mode": "rgb",
124	 *     "color": {"r": 255, "g": 128, "b": 0}
125	 *   }
126	 *
127	 * 使用 retain = 1 确保 Home Assistant 重新订阅时能立即获取最新状态。
128	 * 消息发布到全局变量 pwm_state_topic（由 device_id 模块初始化）。
129	 */
130	static void publish_pwm_state(void)
131	{
132	    // 从 led_control 模块获取 PWM 灯的当前硬件状态
133	    led_state_t *state = led_pwm_get_state();
134	
135	    // 构建 JSON 对象
136	    cJSON *root = cJSON_CreateObject();
137	    cJSON_AddStringToObject(root, "state", state->state ? "ON" : "OFF");
138	    cJSON_AddNumberToObject(root, "brightness", state->brightness);
139	    cJSON_AddStringToObject(root, "color_mode", "rgb");
140	
141	    // 嵌套 color 对象
142	    cJSON *color = cJSON_CreateObject();
143	    cJSON_AddNumberToObject(color, "r", state->red);
144	    cJSON_AddNumberToObject(color, "g", state->green);
145	    cJSON_AddNumberToObject(color, "b", state->blue);
146	    cJSON_AddItemToObject(root, "color", color);
147	
148	    // 序列化为字符串并发布，使用 retain 确保状态持久化
149	    char *state_str = cJSON_Print(root);
150	    if (state_str)
151	    {
152	        mqtt_ha_publish(pwm_state_topic, state_str, 1);
153	        free(state_str);   // cJSON_Print 内部 malloc，需手动释放
154	    }
155	    cJSON_Delete(root);
156	}
157	
158	/**
159	 * @brief  将 WS2812 灯带的当前状态序列化为 JSON 并发布
160	 *
161	 * JSON 格式与 PWM 灯完全一致，仅发布到不同的 topic（ws2812_state_topic）。
162	 * 为保持与 Home Assistant 的兼容性，color_mode 固定为 "rgb"。
163	 */
164	static void publish_ws2812_state(void)
165	{
166	    led_state_t *state = led_ws2812_get_state();
167	
168	    cJSON *root = cJSON_CreateObject();
169	    cJSON_AddStringToObject(root, "state", state->state ? "ON" : "OFF");
170	    cJSON_AddNumberToObject(root, "brightness", state->brightness);
171	    cJSON_AddStringToObject(root, "color_mode", "rgb");
172	
173	    cJSON *color = cJSON_CreateObject();
174	    cJSON_AddNumberToObject(color, "r", state->red);
175	    cJSON_AddNumberToObject(color, "g", state->green);
176	    cJSON_AddNumberToObject(color, "b", state->blue);
177	    cJSON_AddItemToObject(root, "color", color);
178	
179	    char *state_str = cJSON_Print(root);
180	    if (state_str)
181	    {
182	        mqtt_ha_publish(ws2812_state_topic, state_str, 1);
183	        free(state_str);
184	    }
185	    cJSON_Delete(root);
186	}
187	
188	/*===========================================================================
189	 * 命令处理函数
190	 *===========================================================================*/
191	
192	/**
193	 * @brief  解析并执行 PWM RGB 灯的 JSON 控制命令
194	 *
195	 * 从 MQTT command topic 接收到的消息通过此函数处理。
196	 * 支持的 JSON 字段（均为可选，按需更新）：
197	 *   - "state"       : "ON" 或 "OFF"，控制开关
198	 *   - "brightness"  : 0-255 整数，控制整体亮度
199	 *   - "color"       : {"r":0-255, "g":0-255, "b":0-255} 对象
200	 *
201	 * 设计要点：
202	 *   1. 增量更新：只有实际变更的字段才触发硬件更新，避免不必要的 LED 闪烁
203	 *   2. 范围裁剪：brightness 被限制在 [0, 255] 范围内，防止异常值
204	 *   3. 状态同步：更新硬件后立即调用 publish_pwm_state() 反馈结果
205	 *   4. 容错处理：JSON 解析失败时静默返回，不产生副作用
206	 *
207	 * 亮度计算公式（led_control 模块内部实现）：
208	 *   duty = state ? (color * brightness) / 255 : 0
209	 *   即：灯关闭时 duty 为 0；打开时颜色分量按亮度比例缩放
210	 *
211	 * @param data     指向接收到的原始 JSON 字符串（可能不含 '\0' 结尾）
212	 * @param data_len 数据长度（字节）
213	 */
214	static void handle_pwm_command(const char *data, int data_len)
215	{
216	    // 解析 JSON，使用带长度的版本避免字符串截断问题
217	    cJSON *root = cJSON_ParseWithLength(data, data_len);
218	    if (!root)
219	        return;  // JSON 无效，静默丢弃
220	
221	    // 获取当前状态作为基准，new_state 用作增量修改
222	    led_state_t *state = led_pwm_get_state();
223	    led_state_t new_state = *state;
224	    bool need_update = false;
225	
226	    // ---- 解析 "state" 字段（开关） ----
227	    cJSON *state_item = cJSON_GetObjectItem(root, "state");
228	    if (cJSON_IsString(state_item))
229	    {
230	        bool s = (strcmp(state_item->valuestring, "ON") == 0);
231	        if (s != state->state)
232	        {
233	            new_state.state = s;
234	            need_update = true;
235	        }
236	    }
237	
238	    // ---- 解析 "brightness" 字段（0-255） ----
239	    cJSON *brightness_item = cJSON_GetObjectItem(root, "brightness");
240	    if (cJSON_IsNumber(brightness_item))
241	    {
242	        int b = brightness_item->valueint;
243	        // 裁剪到有效范围，防御异常输入
244	        if (b < 0)  b = 0;
245	        if (b > 255) b = 255;
246	        if (b != state->brightness)
247	        {
248	            new_state.brightness = b;
249	            need_update = true;
250	        }
251	    }
252	
253	    // ---- 解析 "color" 字段（RGB 对象） ----
254	    cJSON *color_item = cJSON_GetObjectItem(root, "color");
255	    if (cJSON_IsObject(color_item))
256	    {
257	        cJSON *r = cJSON_GetObjectItem(color_item, "r");
258	        cJSON *g = cJSON_GetObjectItem(color_item, "g");
259	        cJSON *b = cJSON_GetObjectItem(color_item, "b");
260	        if (cJSON_IsNumber(r) && cJSON_IsNumber(g) && cJSON_IsNumber(b))
261	        {
262	            uint8_t red   = r->valueint;
263	            uint8_t green = g->valueint;
264	            uint8_t blue  = b->valueint;
265	            if (red != state->red || green != state->green || blue != state->blue)
266	            {
267	                new_state.red   = red;
268	                new_state.green = green;
269	                new_state.blue  = blue;
270	                need_update = true;
271	            }
272	        }
273	    }
274	
275	    // 仅在确实有变化时更新硬件并反馈状态，避免不必要的 I/O 操作
276	    if (need_update)
277	    {
278	        *state = new_state;
279	        led_pwm_set_state(state);      // 写入 LEDC 硬件 PWM 占空比
280	        publish_pwm_state();          // 反馈新状态到 Home Assistant
281	    }
282	
283	    cJSON_Delete(root);
284	}
285	
286	/**
287	 * @brief  解析并执行 WS2812 灯带的 JSON 控制命令
288	 *
289	 * 与 handle_pwm_command() 逻辑完全一致，区别在于：
290	 *   - 操作的硬件对象是 WS2812 灯带（通过 RMT 接口驱动）
291	 *   - 状态读写使用 led_ws2812_* 系列函数
292	 *   - 反馈状态发布到 ws2812_state_topic
293	 *
294	 * 注意：Home Assistant 将 PWM 灯和 WS2812 灯带视为两个独立的 light 实体，
295	 *       因此需要分别处理各自的 command topic。
296	 *
297	 * @param data     指向接收到的原始 JSON 字符串
298	 * @param data_len 数据长度（字节）
299	 */
300	static void handle_ws2812_command(const char *data, int data_len)
301	{
302	    cJSON *root = cJSON_ParseWithLength(data, data_len);
303	    if (!root)
304	        return;
305	
306	    led_state_t *state = led_ws2812_get_state();
307	    led_state_t new_state = *state;
308	    bool need_update = false;
309	
310	    // 解析开关状态
311	    cJSON *state_item = cJSON_GetObjectItem(root, "state");
312	    if (cJSON_IsString(state_item))
313	    {
314	        bool s = (strcmp(state_item->valuestring, "ON") == 0);
315	        if (s != state->state)
316	        {
317	            new_state.state = s;
318	            need_update = true;
319	        }
320	    }
321	
322	    // 解析亮度（0-255，裁剪到有效范围）
323	    cJSON *brightness_item = cJSON_GetObjectItem(root, "brightness");
324	    if (cJSON_IsNumber(brightness_item))
325	    {
326	        int b = brightness_item->valueint;
327	        if (b < 0)  b = 0;
328	        if (b > 255) b = 255;
329	        if (b != state->brightness)
330	        {
331	            new_state.brightness = b;
332	            need_update = true;
333	        }
334	    }
335	
336	    // 解析 RGB 颜色
337	    cJSON *color_item = cJSON_GetObjectItem(root, "color");
338	    if (cJSON_IsObject(color_item))
339	    {
340	        cJSON *r = cJSON_GetObjectItem(color_item, "r");
341	        cJSON *g = cJSON_GetObjectItem(color_item, "g");
342	        cJSON *b = cJSON_GetObjectItem(color_item, "b");
343	        if (cJSON_IsNumber(r) && cJSON_IsNumber(g) && cJSON_IsNumber(b))
344	        {
345	            uint8_t red   = r->valueint;
346	            uint8_t green = g->valueint;
347	            uint8_t blue  = b->valueint;
348	            if (red != state->red || green != state->green || blue != state->blue)
349	            {
350	                new_state.red   = red;
351	                new_state.green = green;
352	                new_state.blue  = blue;
353	                need_update = true;
354	            }
355	        }
356	    }
357	
358	    // 仅在状态有实际变化时驱动硬件
359	    if (need_update)
360	    {
361	        *state = new_state;
362	        led_ws2812_set_state(state);  // 刷新 WS2812 灯带所有像素
363	        publish_ws2812_state();       // 反馈新状态
364	    }
365	
366	    cJSON_Delete(root);
367	}
368	
369	/*===========================================================================
370	 * MQTT 事件处理
371	 *===========================================================================*/
372	
373	/**
374	 * @brief  MQTT 客户端事件回调函数（esp_mqtt_client 事件循环的核心入口）
375	 *
376	 * 处理两类主要事件：
377	 *
378	 *   【MQTT_EVENT_CONNECTED — 连接成功】
379	 *   Broker 连接建立后触发，此时执行一次性初始化工作：
380	 *     1. 发布在线状态（"online" → availability topic）
381	 *     2. 订阅 PWM 灯和 WS2812 灯的命令主题（command topic）
382	 *     3. 为每个实体发送 Home Assistant MQTT Discovery 配置消息
383	 *        （包含名称、唯一 ID、命令/状态主题、设备信息等）
384	 *     4. 发布当前灯光状态，同步硬件实际状态到 Home Assistant
385	 *
386	 *   注意：发现配置使用 retain = 1，确保 HA 重启后能自动恢复实体注册。
387	 *
388	 *   【MQTT_EVENT_DATA — 收到消息】
389	 *   根据消息的 topic 判断是哪个实体的命令：
390	 *     - 匹配 pwm_command_topic     → handle_pwm_command()
391	 *     - 匹配 ws2812_command_topic  → handle_ws2812_command()
392	 *
393	 * @param handler_args 注册回调时传入的用户参数（此处未使用，为 NULL）
394	 * @param base         事件基（ESP-IDF 事件系统概念，此处固定为 MQTT_EVENT）
395	 * @param event_id     具体事件 ID，参见 esp_mqtt_event_id_t 枚举
396	 * @param event_data   指向 esp_mqtt_event_t 结构体的事件数据
397	 */
398	static void mqtt_event_handler(void *handler_args, esp_event_base_t base,
399	                               int32_t event_id, void *event_data)
400	{
401	    esp_mqtt_event_handle_t event = event_data;
402	    esp_mqtt_client_handle_t client = event->client;
403	
404	    switch ((esp_mqtt_event_id_t)event_id)
405	    {
406	    /*----------------------------------------------------------------------
407	     * MQTT 连接成功 — 初始化 Home Assistant 集成
408	     *--------------------------------------------------------------------*/
409	    case MQTT_EVENT_CONNECTED:
410	        ESP_LOGI(TAG, "MQTT connected");
411	
412	        // 1. 发布在线状态，Home Assistant 据此将设备标记为"可用"
413	        mqtt_ha_publish(device_avail_topic, "online", 1);
414	
415	        // 2. 订阅两个灯的命令主题，QoS=1
416	        esp_mqtt_client_subscribe(client, pwm_command_topic, 1);
417	        esp_mqtt_client_subscribe(client, ws2812_command_topic, 1);
418	
419	        /*------------------------------------------------------------------
420	         * 3. 发布 PWM RGB 灯的 Home Assistant 发现配置
421	         *
422	         * Home Assistant MQTT Discovery 规范说明：
423	         *   消息发布到 <discovery_prefix>/<component>/<object_id>/config
424	         *   本项目中 discovery_prefix = "homeassistant"（HA 默认值）
425	         *
426	         * 关键字段说明：
427	         *   name         — 实体在 HA 界面中显示的名称
428	         *   unique_id    — 全局唯一标识，必须唯一，否则实体会被覆盖
429	         *   cmd_t        — 接收命令的 topic（HA 向此 topic 发布控制指令）
430	         *   stat_t       — 状态上报的 topic（设备向此 topic 发布状态）
431	         *   schema       — 命令格式，"json" 表示使用 JSON 命令
432	         *   brightness   — true 表示支持亮度调节
433	         *   supported_color_modes — 支持的颜色模式列表
434	         *   optimistic   — false 表示设备会反馈状态（非乐观模式）
435	         *   avty_t       — availability topic，用于在线/离线检测
436	         *   device       — 设备信息对象，将两个 light 实体关联到同一物理设备
437	         *------------------------------------------------------------------*/
438	        {
439	            cJSON *cfg = cJSON_CreateObject();
440	            cJSON_AddStringToObject(cfg, "name", "PWM RGB Light");
441	            cJSON_AddStringToObject(cfg, "unique_id", base_device_id);
442	            cJSON_AddStringToObject(cfg, "cmd_t", pwm_command_topic);
443	            cJSON_AddStringToObject(cfg, "stat_t", pwm_state_topic);
444	            cJSON_AddStringToObject(cfg, "schema", "json");
445	            cJSON_AddBoolToObject(cfg, "brightness", true);
446	
447	            // 支持的色彩模式：RGB（通过红绿蓝三通道独立调节）
448	            cJSON *cm = cJSON_CreateArray();
449	            cJSON_AddItemToArray(cm, cJSON_CreateString("rgb"));
450	            cJSON_AddItemToObject(cfg, "supported_color_modes", cm);
451	
452	            // optimistic=false 表示设备会主动反馈状态，HA 等待状态确认
453	            cJSON_AddBoolToObject(cfg, "optimistic", false);
454	            cJSON_AddStringToObject(cfg, "avty_t", device_avail_topic);
455	
456	            // 设备信息：将 PWM 灯和 WS2812 灯关联到同一物理 ESP32 设备
457	            cJSON *dev = cJSON_CreateObject();
458	            cJSON_AddStringToObject(dev, "identifiers", base_device_id);
459	            cJSON_AddStringToObject(dev, "name", base_device_name);
460	            cJSON_AddStringToObject(dev, "model", "ESP32 Dual RGB Light");
461	            cJSON_AddStringToObject(dev, "manufacturer", "Espressif");
462	            cJSON_AddItemToObject(cfg, "device", dev);
463	
464	            char *cfg_str = cJSON_Print(cfg);
465	            if (cfg_str)
466	            {
467	                mqtt_ha_publish(pwm_config_topic, cfg_str, 1);
468	                free(cfg_str);
469	            }
470	            cJSON_Delete(cfg);
471	        }
472	
473	        /*------------------------------------------------------------------
474	         * 4. 发布 WS2812 灯带的 Home Assistant 发现配置
475	         *
476	         * 与 PWM 灯类似，区别在于：
477	         *   - unique_id 添加 "_ws2812" 后缀，确保与 PWM 灯实体不冲突
478	         *   - command/state topic 使用 ws2812 专属主题
479	         *   - 共享同一个 device 信息（通过 base_device_id 关联）
480	         *------------------------------------------------------------------*/
481	        {
482	            cJSON *cfg = cJSON_CreateObject();
483	            cJSON_AddStringToObject(cfg, "name", "WS2812 LED Strip");
484	
485	            // unique_id 必须在 HA 中唯一，添加后缀避免与 PWM 灯冲突
486	            char uid[32];
487	            snprintf(uid, sizeof(uid), "%s_ws2812", base_device_id);
488	            cJSON_AddStringToObject(cfg, "unique_id", uid);
489	
490	            cJSON_AddStringToObject(cfg, "cmd_t", ws2812_command_topic);
491	            cJSON_AddStringToObject(cfg, "stat_t", ws2812_state_topic);
492	            cJSON_AddStringToObject(cfg, "schema", "json");
493	            cJSON_AddBoolToObject(cfg, "brightness", true);
494	
495	            cJSON *cm = cJSON_CreateArray();
496	            cJSON_AddItemToArray(cm, cJSON_CreateString("rgb"));
497	            cJSON_AddItemToObject(cfg, "supported_color_modes", cm);
498	
499	            cJSON_AddBoolToObject(cfg, "optimistic", false);
500	            cJSON_AddStringToObject(cfg, "avty_t", device_avail_topic);
501	
502	            cJSON *dev = cJSON_CreateObject();
503	            cJSON_AddStringToObject(dev, "identifiers", base_device_id);
504	            cJSON_AddItemToObject(cfg, "device", dev);
505	
506	            char *cfg_str = cJSON_Print(cfg);
507	            if (cfg_str)
508	            {
509	                mqtt_ha_publish(ws2812_config_topic, cfg_str, 1);
510	                free(cfg_str);
511	            }
512	            cJSON_Delete(cfg);
513	        }
514	
515	        /*------------------------------------------------------------------
516	         * 5. 发布 Wi-Fi RSSI 传感器的 Home Assistant 发现配置
517	         *
518	         * 这是一个诊断类实体（entity_category: "diagnostic"），
519	         * 不会出现在默认仪表盘上，用户需手动添加到 Lovelace 卡片。
520	         *
521	         * 关键字段：
522	         *   device_class      — "signal_strength" 信号强度类别
523	         *   state_class       — "measurement" 表示连续测量值
524	         *   entity_category   — "diagnostic" 诊断信息，默认隐藏
525	         *   unit_of_measurement — "dBm" 分贝毫瓦
526	         *------------------------------------------------------------------*/
527	        {
528	            cJSON *cfg = cJSON_CreateObject();
529	            cJSON_AddStringToObject(cfg, "name", "Wi-Fi RSSI");
530	            cJSON_AddStringToObject(cfg, "state_topic", rssi_state_topic);
531	            cJSON_AddStringToObject(cfg, "unit_of_measurement", "dBm");
532	            cJSON_AddStringToObject(cfg, "device_class", "signal_strength");
533	            cJSON_AddStringToObject(cfg, "state_class", "measurement");
534	            cJSON_AddStringToObject(cfg, "entity_category", "diagnostic");
535	
536	            char uid[32];
537	            snprintf(uid, sizeof(uid), "wifi_rssi_%s", base_device_id);
538	            cJSON_AddStringToObject(cfg, "unique_id", uid);
539	
540	            cJSON *dev = cJSON_CreateObject();
541	            cJSON_AddStringToObject(dev, "identifiers", base_device_id);
542	            cJSON_AddItemToObject(cfg, "device", dev);
543	
544	            // 使用 PrintUnformatted 减少消息体积（诊断配置不需要可读性）
545	            char *cfg_str = cJSON_PrintUnformatted(cfg);
546	            if (cfg_str)
547	            {
548	                mqtt_ha_publish(rssi_config_topic, cfg_str, 1);
549	                free(cfg_str);
550	            }
551	            cJSON_Delete(cfg);
552	        }
553	
554	        // 6. 发布当前灯光状态，确保 Home Assistant 显示与硬件实际一致
555	        publish_pwm_state();
556	        publish_ws2812_state();
557	
558	        break;
559	
560	    /*----------------------------------------------------------------------
561	     * MQTT 数据接收 — 命令分发
562	     *
563	     * 根据消息的 topic 长度和内容精确匹配，将命令路由到对应的处理器。
564	     * 使用 topic_len + strncmp 而非 strcmp，因为 MQTT 消息中 topic
565	     * 可能不以 '\0' 结尾。
566	     *--------------------------------------------------------------------*/
567	    case MQTT_EVENT_DATA:
568	        // 判断是否为 PWM 灯的命令
569	        if (event->topic_len == strlen(pwm_command_topic) &&
570	            strncmp(event->topic, pwm_command_topic, event->topic_len) == 0)
571	        {
572	            handle_pwm_command(event->data, event->data_len);
573	        }
574	        // 判断是否为 WS2812 灯的命令
575	        else if (event->topic_len == strlen(ws2812_command_topic) &&
576	                 strncmp(event->topic, ws2812_command_topic, event->topic_len) == 0)
577	        {
578	            handle_ws2812_command(event->data, event->data_len);
579	        }
580	        // （可在此处扩展更多 command topic 的处理）
581	
582	        break;
583	
584	    /*----------------------------------------------------------------------
585	     * 其他事件（DISCONNECTED、ERROR、BEFORE_CONNECT 等）
586	     * 由 esp_mqtt_client 内部自动处理重连，此处不需要额外逻辑
587	     *--------------------------------------------------------------------*/
588	    default:
589	        break;
590	    }
591	}
592	
593	/*===========================================================================
594	 * 模块初始化
595	 *===========================================================================*/
596	
597	/**
598	 * @brief  初始化 MQTT 客户端并启动 Home Assistant 集成
599	 *
600	 * 初始化流程：
601	 *   1. 读取 Wi-Fi STA MAC 地址，生成唯一的 MQTT Client ID
602	 *      （格式：ESP32_AABBCCDDEEFF）
603	 *   2. 构建 MQTT 配置结构体：
604	 *        - Broker URI 来自 Kconfig（menuconfig 中设置）
605	 *        - Client ID 基于 MAC 地址，确保同一 Broker 下不冲突
606	 *        - 协议版本 MQTT 3.1.1
607	 *        - 自动重连已启用
608	 *        - LWT（遗嘱消息）：设备异常断开时，Broker 自动发布 "offline"
609	 *   3. 创建并注册 MQTT 事件回调
610	 *   4. 启动 MQTT 客户端（异步，连接成功后会回调 MQTT_EVENT_CONNECTED）
611	 *
612	 * @note  LWT 使用 availability topic 和 retain 标志，
613	 *        确保 Home Assistant 能正确追踪设备的在线/离线状态
614	 */
615	void mqtt_ha_init(void)
616	{
617	    /*----------------------------------------------------------------------
618	     * 生成唯一的 MQTT Client ID
619	     *
620	     * 使用 Wi-Fi STA 接口的 MAC 地址（烧录在 eFuse 中，全球唯一）。
621	     * 格式：ESP32_XXXXXXXXXXXX（12 位大写十六进制）
622	     * 这确保了同一网络中多个 ESP32 设备不会产生 Client ID 冲突。
623	     *--------------------------------------------------------------------*/
624	    uint8_t mac[6];
625	    esp_read_mac(mac, ESP_MAC_WIFI_STA);
626	    char client_id[32];
627	    snprintf(client_id, sizeof(client_id), "ESP32_%02X%02X%02X%02X%02X%02X",
628	             mac[0], mac[1], mac[2], mac[3], mac[4], mac[5]);
629	
630	    /*----------------------------------------------------------------------
631	     * 配置 MQTT 客户端
632	     *
633	     * 使用 C99 指定初始化器（designated initializer）语法。
634	     * 关键配置项：
635	     *   - broker.address.uri          : MQTT Broker 地址（如 mqtt://192.168.1.100:1883）
636	     *   - credentials.client_id       : 客户端标识
637	     *   - session.protocol_ver        : MQTT 3.1.1（兼容性最广）
638	     *   - network.disable_auto_reconnect : false 即启用自动重连
639	     *   - session.last_will           : 遗嘱消息配置
640	     *       * topic  = device_avail_topic（设备可用性主题）
641	     *       * msg    = "offline"
642	     *       * qos    = 1
643	     *       * retain = true（持久化，确保新订阅者也能读到）
644	     *--------------------------------------------------------------------*/
645	    esp_mqtt_client_config_t mqtt_cfg = {0};
646	    mqtt_cfg.broker.address.uri = CONFIG_MQTT_BROKER_URL;  // 从 Kconfig / menuconfig 读取
647	    mqtt_cfg.credentials.client_id = client_id;
648	    mqtt_cfg.session.protocol_ver = MQTT_PROTOCOL_V_3_1_1;
649	    mqtt_cfg.network.disable_auto_reconnect = false;       // 启用自动重连
650	    mqtt_cfg.session.last_will.topic = device_avail_topic;  // 遗嘱主题：设备可用性
651	    mqtt_cfg.session.last_will.msg = "offline";             // 遗嘱消息：离线
652	    mqtt_cfg.session.last_will.qos = 1;                     // QoS 1
653	    mqtt_cfg.session.last_will.retain = true;               // 保留遗嘱消息
654	
655	    // 创建 MQTT 客户端实例，注册事件处理器
656	    mqtt_client = esp_mqtt_client_init(&mqtt_cfg);
657	    esp_mqtt_client_register_event(mqtt_client, ESP_EVENT_ANY_ID, mqtt_event_handler, NULL);
658	
659	    // 启动 MQTT 客户端（异步方式，立即返回）
660	    // 客户端会在后台线程中尝试连接 Broker，成功后回调 MQTT_EVENT_CONNECTED
661	    esp_mqtt_client_start(mqtt_client);
662	}

